const items = $input.all();
const outputs = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const text = item.json?.['chatInput'] || '';
  const bin = item.binary || {};

  // 获取当前 item 下所有的二进制字段名 (如 data0, data1, data2)
  const binaryKeys = Object.keys(bin);

  if (binaryKeys.length > 0) {
    // 动态遍历所有图片
    for (const key of binaryKeys) {
      const b = bin[key];

      // 确保该 key 确实包含二进制数据
      if (b) {
        // 使用当前 item 的索引 i 和对应的 key 获取 Buffer
        const buffer = await this.helpers.getBinaryDataBuffer(i, key); 
        const base64 = buffer.toString('base64');
        const mime = b.mimeType || 'image/jpeg';

        outputs.push({
          json: {
            text_11: text,
            filename: b.fileName || `${key}.jpg`,
            image_url_full: `data:${mime};base64,${base64}`,
          },
        });
      }
    }
  } else {
    // 如果没有图片，保留纯文字输出
    outputs.push({ 
      json: { 
        text_11: text, 
        image_url_full: '' 
      } 
    });
  }
}

return outputs;

