const items = $input.all();

const toStr = (v) => (v == null ? '' : String(v).trim());

const collectPrompts = () => {
  const out = [];
  for (const it of items) {
    // 1. 定位 Gemini 返回的核心文本
    const text = it.json?.candidates?.[0]?.content?.parts?.[0]?.text;
    let s = toStr(text);

    if (s) {
      // 2. 清洗数据：去掉开头的 ```json 和 [ 以及结尾的 ] ``` 
      // 同时也处理掉可能存在的 JSON 包装符号
      s = s.replace(/^```json\s*\[?\n?/, '') // 去掉开头的 ```json 和 [
           .replace(/\n?\]?\s*```$/, '')      // 去掉结尾的 ] 和 ```
           .trim();

      // 3. 将转义的换行符 \\n 替换为真实的换行或空格（根据你的需求，这里替换为真实换行）
      // 如果你希望完全连成一段话，可以把 '\n' 改成 ' '
      s = s.replace(/\\n/g, '\n');

      out.push(s);
    }
  }
  return Array.from(new Set(out));
};

const prompts = collectPrompts();

// 最终输出：确保结果干净且只有 1 个 item
return [{
  json: {
    prompt: prompts[0] || "" 
  }
}];
